// NODE: Select Concept
// Weighted random concept pick + vibe + appStyle + gender selection
// Mode: Run Once for All Items

const concepts = $input.all().map(item => item.json);

if (concepts.length === 0) {
  throw new Error('No active concepts found in Airtable');
}

// --- Weighted random selection ---
function weightedRandom(items, weightField) {
  const totalWeight = items.reduce((sum, item) => sum + (Number(item[weightField]) || 1), 0);
  let random = Math.random() * totalWeight;
  for (const item of items) {
    random -= (Number(item[weightField]) || 1);
    if (random <= 0) return item;
  }
  return items[items.length - 1];
}

const concept = weightedRandom(concepts, 'weight');

// --- Vibe selection (toxic only â most viral) ---
function pickVibe() {
  return 'toxic';
}

// --- App style (iMessage only for now) ---
function pickAppStyle() {
  return 'imessage';
}

// --- Gender: ALWAYS male (girl analyzes a guy) ---
const personGender = 'male';

// Use forced_vibe from Airtable if set, otherwise random
const vibe = concept.forced_vibe || pickVibe();
const appStyle = pickAppStyle();
const scenarioName = vibe + '-' + concept.concept_id + '-' + Date.now();

// Body clip count from Airtable (default 3, min 2, max 5)
const bodyClipCount = Math.min(5, Math.max(2, Number(concept.body_clip_count) || 3));

return [{
  json: {
    concept,
    vibe,
    appStyle,
    personGender,
    scenarioName,
    conceptId: concept.concept_id,
    bodyClipCount
  }
}];

// NODE: Validate Scenario
// Parses Gemini response and validates the ContentScenario JSON
// Mode: Run Once for All Items

// Basic LLM Chain outputs { text: "..." } with the raw LLM response
const llmOutput = $input.first().json;
const { vibe } = $('Select Concept').first().json;

// --- JSON Repair utility ---
function repairJson(raw) {
  let s = raw;

  // 1. Strip markdown code fences
  s = s.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // 2. Extract JSON object if there's text before/after it
  const firstBrace = s.indexOf('{');
  const lastBrace = s.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    s = s.substring(firstBrace, lastBrace + 1);
  }

  // 3. Remove control characters inside strings (except \n \r \t)
  // Replace literal tabs, carriage returns that break JSON
  s = s.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');

  // 4. Fix unescaped newlines inside JSON strings
  // Walk through and escape newlines that are inside string values
  let result = '';
  let inString = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (escaped) {
      result += ch;
      escaped = false;
      continue;
    }
    if (ch === '\\') {
      result += ch;
      escaped = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      result += ch;
      continue;
    }
    if (inString && ch === '\n') {
      result += '\\n';
      continue;
    }
    if (inString && ch === '\r') {
      continue; // skip carriage returns
    }
    result += ch;
  }
  s = result;

  // 5. Fix trailing commas before } or ]
  s = s.replace(/,\s*([\]}])/g, '$1');

  // 6. Fix unescaped double quotes inside strings (heuristic)
  // Look for patterns like: "text "quoted" more" and fix to "text \"quoted\" more"
  // This is tricky so we only do a conservative fix: doubled quotes "" -> \"
  // (DeepSeek sometimes outputs "" inside strings)
  s = s.replace(/([^\\])""/g, '$1\\"');

  return s;
}

// Extract JSON from LLM output
// The output parser may have already parsed it into an object
let scenario;
try {
  const raw = llmOutput.output || llmOutput.text || llmOutput;

  if (typeof raw === 'object' && raw !== null) {
    // Already parsed by Structured Output Parser
    scenario = raw;
  } else {
    // Raw string â parse with repair
    const repaired = repairJson(String(raw));
    scenario = JSON.parse(repaired);
  }
} catch (e1) {
  try {
    const raw = llmOutput.output || llmOutput.text || llmOutput;
    let repaired = repairJson(String(raw));
    repaired = repaired.replace(/[\u201C\u201D\u2018\u2019]/g, '"');
    const posMatch = e1.message.match(/position (\d+)/);
    if (posMatch) {
      const pos = parseInt(posMatch[1]);
      repaired = repaired.substring(0, pos) + '\\' + repaired.substring(pos);
    }
    scenario = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { valid: false, errors: ['JSON parse failed after repair: ' + e1.message], scenario: null } }];
  }
}

const errors = [];

// --- Required top-level fields ---
if (!scenario.id) errors.push('Missing id');
if (!scenario.chat) errors.push('Missing chat');
if (!scenario.results) errors.push('Missing results');

if (scenario.chat) {
  if (!scenario.chat.contactName) errors.push('Missing chat.contactName');
  if (!['imessage', 'instagram', 'whatsapp'].includes(scenario.chat.appStyle)) {
    errors.push('Invalid appStyle: ' + scenario.chat.appStyle);
  }
  if (!Array.isArray(scenario.chat.messages) || scenario.chat.messages.length < 12) {
    errors.push('Too few messages: ' + (scenario.chat.messages ? scenario.chat.messages.length : 0) + ' (min 12)');
  }
  if (scenario.chat.messages && scenario.chat.messages.length > 25) {
    errors.push('Too many messages: ' + scenario.chat.messages.length + ' (max 25)');
  }
  // Validate each message
  if (scenario.chat.messages) {
    scenario.chat.messages.forEach((msg, i) => {
      if (!['them', 'me'].includes(msg.sender)) errors.push('Message ' + i + ': invalid sender "' + msg.sender + '"');
      if (!msg.text || typeof msg.text !== 'string') errors.push('Message ' + i + ': missing or invalid text');
    });

    // --- Chat toxicity check: "them" messages must contain actual conflict/tension ---
    const theirMessages = scenario.chat.messages.filter(m => m.sender === 'them').map(m => m.text.toLowerCase());
    const allTheirText = theirMessages.join(' ');
    const TOXIC_INDICATORS = [
      'dramatic', 'chill', 'relax', 'calm down', 'whatever', 'idc', 'i don\'t care',
      'why does it matter', 'big deal', 'overreact', 'insecure', 'crazy', 'psycho',
      'it\'s not like that', 'just a friend', 'you always', 'k', 'fine', 'i never said',
      'that\'s not what', 'leave me alone', 'i don\'t have time', 'i was busy',
      'stop', 'enough', 'you\'re tripping', 'not my problem', 'lol ok', 'bye',
      'who cares', 'get over it', '...', 'nah', 'smh', 'bro', 'dude'
    ];
    const toxicHits = TOXIC_INDICATORS.filter(t => allTheirText.includes(t));
    if (toxicHits.length < 2) {
      errors.push('Chat lacks toxicity: "them" messages contain only ' + toxicHits.length + ' toxic indicators (need 2+). Chat may be too boring/normal.');
    }
  }
}

const r = scenario.results;
if (r) {
  // --- personName auto-fix ---
  const expectedName = r.personGender === 'male' ? 'Him' : 'Her';
  if (r.personName !== expectedName) {
    errors.push('personName should be "' + expectedName + '", got "' + r.personName + '" (auto-fixed)');
    r.personName = expectedName;
  }

  // --- Scores 0-100 ---
  const scoreFields = ['overallScore', 'warmthScore', 'communicationScore', 'dramaScore', 'distanceScore', 'passionScore'];
  scoreFields.forEach(field => {
    const val = r[field];
    if (typeof val !== 'number' || val < 0 || val > 100) {
      errors.push(field + ' out of range: ' + val);
    }
  });

  // --- Hard-code: toxic score must be 70+ (overallScore â¤ 30) for all vibes ---
  if (typeof r.overallScore === 'number' && r.overallScore > 30) {
    errors.push('overallScore=' + r.overallScore + ' too high (max 30, toxic score must be 70+) â auto-fixed to 30');
    r.overallScore = 30;
  }

  // --- Valid soul type IDs ---
  const MALE_SOUL_TYPES = [
    'male-untamable', 'male-gentle-flame', 'male-silent-abyss', 'male-faded-crown',
    'male-sweet-poison', 'male-wounded-prince', 'male-burning-promise', 'male-final-silence',
    'male-dark-mirror', 'male-ice-charmer', 'male-silent-choke', 'male-shifting-flame',
    'male-chameleon', 'male-star-collector'
  ];
  const FEMALE_SOUL_TYPES = [
    'female-love-rush', 'female-natural-state', 'female-fire-dance', 'female-frozen-bloom',
    'female-torn-silk', 'female-inner-voice', 'female-silent-venom', 'female-sunset-soul',
    'female-deep-shadow', 'female-wild-luxury', 'female-living-maze', 'female-golden-rule',
    'female-savage-grace', 'female-quiet-storm', 'female-rising-phoenix', 'female-liquid-mirror'
  ];
  const ALL_SOUL_TYPES = MALE_SOUL_TYPES.concat(FEMALE_SOUL_TYPES);

  if (!ALL_SOUL_TYPES.includes(r.personSoulType)) {
    errors.push('Invalid personSoulType: "' + r.personSoulType + '"');
  }
  if (!ALL_SOUL_TYPES.includes(r.userSoulType)) {
    errors.push('Invalid userSoulType: "' + r.userSoulType + '"');
  }

  // Gender-soul type cross check
  if (r.personGender === 'male' && r.personSoulType && !r.personSoulType.startsWith('male-')) {
    errors.push('personGender=male but personSoulType is not male: ' + r.personSoulType);
  }
  if (r.personGender === 'male' && r.userSoulType && !r.userSoulType.startsWith('female-')) {
    errors.push('personGender=male but userSoulType should be female: ' + r.userSoulType);
  }
  if (r.personGender === 'female' && r.personSoulType && !r.personSoulType.startsWith('female-')) {
    errors.push('personGender=female but personSoulType is not female: ' + r.personSoulType);
  }
  if (r.personGender === 'female' && r.userSoulType && !r.userSoulType.startsWith('male-')) {
    errors.push('personGender=female but userSoulType should be male: ' + r.userSoulType);
  }

  // --- Traits ---
  if (!Array.isArray(r.personTraits) || r.personTraits.length !== 5) {
    errors.push('personTraits must have exactly 5, got ' + (r.personTraits ? r.personTraits.length : 0));
  }
  if (!Array.isArray(r.userTraits) || r.userTraits.length !== 5) {
    errors.push('userTraits must have exactly 5, got ' + (r.userTraits ? r.userTraits.length : 0));
  }

  // Banned traits filter
  const BANNED = ['Early Stage', 'New Connection', 'Fresh Start', 'Getting to Know', 'Just Met', 'Beginning Phase'];
  const allTraits = (r.personTraits || []).concat(r.userTraits || []);
  allTraits.forEach(trait => {
    if (BANNED.some(b => trait.toLowerCase().includes(b.toLowerCase()))) {
      errors.push('Banned trait found: "' + trait + '"');
    }
  });

  // --- Categories ---
  const requiredCategories = ['intentions', 'chemistry', 'effort', 'redFlagsGreenFlags', 'trajectory'];
  requiredCategories.forEach(cat => {
    if (!r.categories || !r.categories[cat] || !r.categories[cat].description) {
      errors.push('Missing or empty category: ' + cat);
    }
  });

  // --- Message Insights ---
  if (!Array.isArray(r.messageInsights)) {
    errors.push('messageInsights is not an array');
  } else {
    if (r.messageInsights.length < 3 || r.messageInsights.length > 6) {
      errors.push('messageInsights count=' + r.messageInsights.length + ' (need 3-6)');
    }

    // Check each insight message is an exact quote from chat
    const chatTexts = (scenario.chat && scenario.chat.messages ? scenario.chat.messages : []).map(m => m.text);
    r.messageInsights.forEach((insight, i) => {
      if (!chatTexts.includes(insight.message)) {
        const insightLower = insight.message.trim().toLowerCase();
        // Try fuzzy match (trimmed, case-insensitive exact)
        let matched = chatTexts.find(t => t.trim().toLowerCase() === insightLower);
        // Try substring match: AI quoted part of a message
        if (!matched) {
          matched = chatTexts.find(t => t.toLowerCase().includes(insightLower));
        }
        // Try reverse substring: chat message is part of AI quote (less common)
        if (!matched) {
          matched = chatTexts.find(t => insightLower.includes(t.toLowerCase()) && t.length > 10);
        }
        if (matched) {
          insight.message = matched; // Auto-fix to exact chat text
        } else {
          errors.push('Insight ' + i + ': message "' + insight.message + '" not found in chat');
        }
      }
      if (!['RED FLAG', 'GREEN FLAG', 'DECODED'].includes(insight.tag)) {
        errors.push('Insight ' + i + ': invalid tag "' + insight.tag + '"');
      }
    });

    // Check DECODED requirement
    const hasDecoded = r.messageInsights.some(ins => ins.tag === 'DECODED');
    if (!hasDecoded) {
      errors.push('No DECODED insight found (at least 1 required)');
    }

    // Auto-remove greeting insights instead of failing
    const GREETING_WORDS = ['hi', 'hey', 'hello', 'sup', 'yo', 'hii', 'hiii', 'heyy', 'heyyy'];
    const beforeCount = r.messageInsights.length;
    r.messageInsights = r.messageInsights.filter(insight => {
      const lower = insight.message.toLowerCase().trim();
      if (GREETING_WORDS.includes(lower)) {
        errors.push('Auto-removed greeting insight: "' + insight.message + '" (non-critical)');
        return false;
      }
      return true;
    });
    if (beforeCount !== r.messageInsights.length) {
      errors.push('Removed ' + (beforeCount - r.messageInsights.length) + ' greeting insight(s) â ' + r.messageInsights.length + ' remaining');
    }
  }

  // --- Dynamic ---
  if (!r.dynamic || !r.dynamic.name) errors.push('Missing dynamic.name');
  if (!r.dynamic || !r.dynamic.whyThisHappens) errors.push('Missing dynamic.whyThisHappens');
  if (r.dynamic && (typeof r.dynamic.powerBalance !== 'number' || r.dynamic.powerBalance < 0 || r.dynamic.powerBalance > 100)) {
    errors.push('dynamic.powerBalance out of range: ' + (r.dynamic ? r.dynamic.powerBalance : 'undefined'));
  }
}

// Determine if we should pass the scenario through (allow minor errors)
const criticalErrors = errors.filter(e =>
  !e.includes('auto-fixed') &&
  !e.includes('out of range') &&
  !e.includes('not found in chat') && // partial quote mismatches are non-critical
  !e.includes('non-critical') &&
  !e.includes('Auto-removed')
);
const valid = criticalErrors.length === 0;

return [{
  json: {
    valid,
    errors,
    scenario: scenario,
    errorCount: errors.length,
    criticalErrorCount: criticalErrors.length
  }
}];

// NODE: Validate Copy
// Validates the Gemini content copy response (new structure with bodyClips)
// Mode: Run Once for All Items

// Basic LLM Chain outputs { text: "..." } with the raw LLM response
const llmOutput = $input.first().json;
const { scenario } = $('Build Copy Prompt').first().json;
const { bodyClipCount } = $('Select Concept').first().json;

// --- JSON Repair utility ---
function repairJson(raw) {
  let s = raw;
  s = s.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const firstBrace = s.indexOf('{');
  const lastBrace = s.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    s = s.substring(firstBrace, lastBrace + 1);
  }
  s = s.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
  let result = '';
  let inString = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (escaped) { result += ch; escaped = false; continue; }
    if (ch === '\\') { result += ch; escaped = true; continue; }
    if (ch === '"') { inString = !inString; result += ch; continue; }
    if (inString && ch === '\n') { result += '\\n'; continue; }
    if (inString && ch === '\r') { continue; }
    result += ch;
  }
  s = result;
  s = s.replace(/,\s*([\]}])/g, '$1');
  s = s.replace(/([^\\])""/g, '$1\\"');
  return s;
}

let copy;
try {
  const raw = llmOutput.output || llmOutput.text || llmOutput;

  if (typeof raw === 'object' && raw !== null) {
    copy = raw;
  } else {
    copy = JSON.parse(repairJson(String(raw)));
  }
} catch (e1) {
  try {
    const raw = llmOutput.output || llmOutput.text || llmOutput;
    let repaired = repairJson(String(raw));
    repaired = repaired.replace(/[\u201C\u201D\u2018\u2019]/g, '"');
    const posMatch = e1.message.match(/position (\d+)/);
    if (posMatch) {
      const pos = parseInt(posMatch[1]);
      repaired = repaired.substring(0, pos) + '\\' + repaired.substring(pos);
    }
    copy = JSON.parse(repaired);
  } catch (e2) {
    return [{ json: { valid: false, errors: ['JSON parse failed after repair: ' + e1.message], copy: null, scenario } }];
  }
}

const errors = [];

// Character limit for all VOs (50 chars = ~3 seconds of natural speech)
const VO_CHAR_LIMIT = 50;
// Hard limit â above this we auto-trim instead of failing
const VO_CHAR_HARD_LIMIT = 65;

// Auto-trim VOs that exceed the character limit (Gemini can't count chars)
function trimVO(vo) {
  // Allow small grace (up to 55) â only actively trim above that
  const TRIM_THRESHOLD = 55;
  if (!vo || vo.length <= TRIM_THRESHOLD) return vo;

  let trimmed = vo;

  // Step 1: Remove trailing filler words
  const TRAILING_FILLERS = [', lol', ' lol', ', honestly', ' honestly', ', like', ' tho', ', bro', ' fr', ', ngl'];
  for (const filler of TRAILING_FILLERS) {
    if (trimmed.toLowerCase().endsWith(filler) || trimmed.toLowerCase().endsWith(filler + '.')) {
      trimmed = trimmed.substring(0, trimmed.length - (trimmed.toLowerCase().endsWith(filler + '.') ? filler.length + 1 : filler.length)).trim();
      // Re-add period if it makes sense
      if (!/[.!?ââ¦]$/.test(trimmed)) trimmed += '.';
      if (trimmed.length <= VO_CHAR_LIMIT) return trimmed;
    }
  }

  // Step 2: If two sentences, try keeping just the first
  const sentenceBreak = trimmed.match(/^(.{20,}?[.!?])\s+/);
  if (sentenceBreak && sentenceBreak[1].length <= VO_CHAR_LIMIT && sentenceBreak[1].length >= 20) {
    return sentenceBreak[1];
  }

  // Step 3: Cut at last word boundary before limit and add ellipsis
  if (trimmed.length > VO_CHAR_LIMIT) {
    const cut = trimmed.substring(0, VO_CHAR_LIMIT - 1);
    const lastSpace = cut.lastIndexOf(' ');
    if (lastSpace > 20) {
      trimmed = cut.substring(0, lastSpace).replace(/[,.\s]+$/, '') + 'â';
    }
  }

  return trimmed;
}

// Valid body clip section IDs
const ALL_SECTION_IDS = ['toxic_score', 'soul_type', 'wtf_happening', 'between_the_lines', 'souls_together'];
const expectedCount = Math.min(5, Math.max(2, bodyClipCount || 3));

// Hook text (max 8 words for short punchy overlay)
if (!copy.hookText || typeof copy.hookText !== 'string') {
  errors.push('Missing hookText');
} else if (copy.hookText.split(' ').length > 10) {
  errors.push('hookText too long: ' + copy.hookText.split(' ').length + ' words (max 8-10)');
}

// Hook VO (50 chars max for 3s speech) â auto-trim if over limit
if (!copy.hookVO || typeof copy.hookVO !== 'string') {
  errors.push('Missing hookVO');
} else {
  const originalHookVO = copy.hookVO;
  copy.hookVO = trimVO(copy.hookVO);
  if (originalHookVO !== copy.hookVO) {
    errors.push('hookVO auto-trimmed: "' + originalHookVO + '" â "' + copy.hookVO + '" (auto-fixed)');
  }
  if (copy.hookVO.length > VO_CHAR_HARD_LIMIT) {
    errors.push('hookVO too long even after trim: ' + copy.hookVO.length + ' chars (max ' + VO_CHAR_LIMIT + '). Text: "' + copy.hookVO + '"');
  }
}

// Body clips
if (!Array.isArray(copy.bodyClips)) {
  errors.push('Missing or invalid bodyClips array');
} else {
  if (copy.bodyClips.length !== expectedCount) {
    errors.push('Expected ' + expectedCount + ' bodyClips, got ' + copy.bodyClips.length);
  }
  copy.bodyClips.forEach((clip, i) => {
    if (!clip.section) {
      errors.push('Body clip ' + i + ': missing section ID');
    } else if (!ALL_SECTION_IDS.includes(clip.section)) {
      errors.push('Body clip ' + i + ': invalid section "' + clip.section + '"');
    }
    if (!clip.text || typeof clip.text !== 'string') {
      errors.push('Body clip ' + i + ' (' + (clip.section || '?') + '): missing text');
    } else if (clip.text.split(' ').length > 8) {
      errors.push('Body clip ' + i + ' (' + (clip.section || '?') + '): text too long (' + clip.text.split(' ').length + ' words, max 6)');
    }
    if (!clip.vo || typeof clip.vo !== 'string') {
      errors.push('Body clip ' + i + ' (' + (clip.section || '?') + '): missing vo');
    } else {
      const originalVO = clip.vo;
      clip.vo = trimVO(clip.vo);
      if (originalVO !== clip.vo) {
        errors.push('Body clip ' + i + ' (' + (clip.section || '?') + '): vo auto-trimmed: "' + originalVO + '" â "' + clip.vo + '" (auto-fixed)');
      }
      if (clip.vo.length > VO_CHAR_HARD_LIMIT) {
        errors.push('Body clip ' + i + ' (' + (clip.section || '?') + '): vo too long even after trim (' + clip.vo.length + ' chars, max ' + VO_CHAR_LIMIT + '). Text: "' + clip.vo + '"');
      }
    }
  });

  // Ensure required sections are present
  const presentSections = copy.bodyClips.map(c => c.section);
  if (!presentSections.includes('toxic_score')) {
    errors.push('Missing required body clip section: toxic_score');
  }
  if (!presentSections.includes('soul_type')) {
    errors.push('Missing required body clip section: soul_type');
  }
}

// Outro text (max 5 words)
if (!copy.outroText || typeof copy.outroText !== 'string') {
  errors.push('Missing outroText');
} else if (copy.outroText.split(' ').length > 7) {
  errors.push('outroText too long: ' + copy.outroText.split(' ').length + ' words (max 5)');
}

// Outro VO (50 chars max for 3s speech) â auto-trim if over limit
if (!copy.outroVO || typeof copy.outroVO !== 'string') {
  errors.push('Missing outroVO');
} else {
  const originalOutroVO = copy.outroVO;
  copy.outroVO = trimVO(copy.outroVO);
  if (originalOutroVO !== copy.outroVO) {
    errors.push('outroVO auto-trimmed: "' + originalOutroVO + '" â "' + copy.outroVO + '" (auto-fixed)');
  }
  if (copy.outroVO.length > VO_CHAR_HARD_LIMIT) {
    errors.push('outroVO too long even after trim: ' + copy.outroVO.length + ' chars (max ' + VO_CHAR_LIMIT + '). Text: "' + copy.outroVO + '"');
  }
}

// Social caption
if (!copy.socialCaption || typeof copy.socialCaption !== 'string') {
  errors.push('Missing socialCaption');
} else if (!copy.socialCaption.toLowerCase().includes('#toxicornah')) {
  copy.socialCaption = copy.socialCaption.trim() + ' #toxicornah';
  errors.push('socialCaption was missing #toxicornah (auto-fixed)');
}

const valid = errors.filter(e => !e.includes('auto-fixed')).length === 0;

return [{
  json: { valid, errors, copy, scenario }
}];

// NODE: Prepare Airtable Save
// Formats the data for saving to the Scenarios table
// Mode: Run Once for All Items

const { concept, vibe, appStyle, scenarioName } = $('Select Concept').first().json;
const { scenario, copy } = $('Validate Copy').first().json;

return [{
  json: {
    scenario_name: scenarioName,
    concept_id: [concept.id],
    vibe: vibe,
    app_style: appStyle,
    scenario_json: JSON.stringify(scenario),
    generated_hook_text: copy.hookText,
    generated_outro_text: copy.outroText,
    generated_vo_script: JSON.stringify(copy.voScript),
    generated_caption_plan: JSON.stringify(copy.captionPlan),
    generated_social_caption: copy.socialCaption,
    status: 'approved'
  }
}];

// NODE: Format Telegram Message
// Builds the Telegram approval message + inline keyboard
// Mode: Run Once for All Items

const { concept, vibe, appStyle, scenarioName } = $('Select Concept').first().json;
const { scenario, copy } = $('Validate Copy').first().json;

const results = scenario.results;

// Toxic Score = inverted health (higher = more toxic)
const toxicScore = 100 - results.overallScore;

// Section name mapping for display
const SECTION_NAMES = {
  toxic_score: 'Toxic Score',
  soul_type: 'His Soul Type',
  wtf_happening: 'WTF Is Happening',
  between_the_lines: 'Between The Lines',
  souls_together: 'Your Souls Together'
};

// Build body clips section for caption
const bodyClipLines = copy.bodyClips.map((clip, i) => {
  const name = SECTION_NAMES[clip.section] || clip.section;
  return '\u{1F3AC} *Clip ' + (i + 1) + ': ' + name + '*\n'
    + '\u{1F4DD} Text: "' + clip.text + '"\n'
    + '\u{1F5E3} VO: "' + clip.vo + '"';
}).join('\n\n');

const caption = '\u{1F3AC} *NEW SCENARIO*\n\n'
  + '\u{1F4CB} *' + concept.concept_name + '*  |  ' + vibe.toUpperCase() + '  |  ' + appStyle + '\n'
  + '\u{1F194} ' + scenarioName + '\n\n'
  + '\u{1F4CA} *Toxic Score:* ' + toxicScore + '/100\n\n'
  + '\u{1F3AD} *Soul Types:*\n'
  + results.personName + ': ' + results.personSoulType + '\n'
  + 'User: ' + results.userSoulType + '\n\n'
  + '\u{1F3F7} *Profile:* ' + results.profileType + ' \u2014 "' + results.profileSubtitle + '"\n\n'
  + '\u26A1 *Dynamic:* ' + results.dynamic.name + '\n\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n'
  + '\u{1F3A4} *HOOK*\n'
  + '\u{1F4DD} Text: "' + copy.hookText + '"\n'
  + '\u{1F5E3} VO: "' + copy.hookVO + '"\n\n'
  + bodyClipLines + '\n\n'
  + '\u{1F3A4} *OUTRO*\n'
  + '\u{1F4DD} Text: "' + copy.outroText + '"\n'
  + '\u{1F5E3} VO: "' + copy.outroVO + '"';

// Inline keyboard for approval
const replyMarkup = {
  inline_keyboard: [
    [
      { text: '\u2705 Approve', callback_data: 'approve_' + scenarioName },
      { text: '\u{1F504} Redo', callback_data: 'redo_' + scenarioName },
      { text: '\u274C Skip', callback_data: 'skip_' + scenarioName }
    ]
  ]
};

// Pass through binary data from Take Screenshot node so Send Photo can access it
return [{
  json: {
    caption,
    replyMarkup,
    scenarioName,
    scenario,
    copy
  },
  binary: $input.first().binary
}];

// NODE: Prepare Screenshot Request
// Prepares the scenario JSON for the screenshot HTTP server
// Mode: Run Once for All Items

const scenarioJson = $('Validate Scenario').first().json.scenario;
const scenarioName = $('Select Concept').first().json.scenarioName;

return [{
  json: {
    scenarioJson,
    scenarioName
  }
}];

